package be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.CheckTriviaal;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ExtractProperty;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementChecker;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementPropertyCalculator;
import be.schaubroeck.lpb.tools.Money;
import lombok.AllArgsConstructor;

import java.util.Collection;
import java.util.Optional;

@AllArgsConstructor
public abstract class AbstractBedragVerdeler implements BedragVerdeler {

    private MoneyKey bedragKey;
    private Money totaalBedrag;
    private LoonElementPropertyCalculator basisCalculator;
    private Money totaalBasis;
    private Collection<LoonElement> loonElementen;
    private LoonElementChecker checker;

    public AbstractBedragVerdeler(
            MoneyKey bedragKey, Money totaalBedrag, LoonElementPropertyCalculator basisCalculator, Money totaalBasis,
            Collection<LoonElement> loonElementen) {
        this(bedragKey, totaalBedrag, basisCalculator, totaalBasis, loonElementen, CheckTriviaal.DEFAULT);
    }

    public AbstractBedragVerdeler(
            MoneyKey bedragKey, Money totaalBedrag, MoneyKey basisKey, Money totaalBasis,
            Collection<LoonElement> loonElementen, LoonElementChecker checker) {
        this(bedragKey, totaalBedrag, new ExtractProperty(basisKey), totaalBasis, loonElementen, checker);
    }

    public AbstractBedragVerdeler(
            MoneyKey bedragKey, Money totaalBedrag, MoneyKey basisKey, Money totaalBasis,
            Collection<LoonElement> loonElementen) {
        this(bedragKey, totaalBedrag, new ExtractProperty(basisKey), totaalBasis, loonElementen, CheckTriviaal.DEFAULT);
    }

    public void verdeelBedragVolgensBasis() {
        if (totaalBedrag.signum() != 0) {
            Money carryover = Money.ZERO;
            for (LoonElement element : loonElementen) {
                Optional<Money> optionalCarryOver =
                        verdeelBedragLoonElementVolgensBasis(bedragKey, totaalBedrag, basisCalculator, totaalBasis, checker, carryover, element);
                if (optionalCarryOver.isPresent()) {
                    carryover = optionalCarryOver.get();
                }
            }
        }
    }

    private Optional<Money> verdeelBedragLoonElementVolgensBasis(
            MoneyKey bedragKey, Money totaalBedrag, LoonElementPropertyCalculator basisCalculator, Money totaalBasis, LoonElementChecker checker,
            Money carryover, LoonElement element) {
        if (checker.check(element)) {
            Money basis = basisCalculator.calculate(element);
            if (basis.signum() != 0) {
                Money bedrag = totaalBedrag.multiply(basis.divide(totaalBasis)).add(carryover);
                return Optional.of(verdeelBedrag(bedragKey, element, bedrag));
            }
        }
        return Optional.empty();
    }
}
